    w.begin_object(10)
    w.write_field("f1")
    w.write_uint64(obj.f1)
    w.write_field("f2")
    w.write_float32(obj.f2)
    w.write_field("f3")
    w.write_float64(obj.f3)
    w.write_field("f4")
    w.write_bytes(obj.f4)
    w.write_field("f5")
    w.write_string(obj.f5)
    w.write_field("f6")
    w.write_bool(obj.f6)
    w.write_field("f7")
    w.write_int32(obj.f7)
    w.write_field("f8")
    w.write_int32(obj.f8)
    w.write_field("f9")
    w.write_int32(obj.f9)
    w.write_field("f10")
    w.write_int64(obj.f10)
    w.end_object
  end

  def self.decode_ten04(r)
    r.begin_object
    obj = Ten04.new
    while r.has_next_field
      key = r.read_field_name
      if key == "f1" then obj.f1 = r.read_uint64; next; end
      if key == "f2" then obj.f2 = r.read_float32; next; end
      if key == "f3" then obj.f3 = r.read_float64; next; end
      if key == "f4" then obj.f4 = r.read_bytes; next; end
      if key == "f5" then obj.f5 = r.read_string; next; end
      if key == "f6" then obj.f6 = r.read_bool; next; end
      if key == "f7" then obj.f7 = r.read_int32; next; end
      if key == "f8" then obj.f8 = r.read_int32; next; end
      if key == "f9" then obj.f9 = r.read_int32; next; end
      if key == "f10" then obj.f10 = r.read_int64; next; end
      r.skip
    end
    r.end_object
    obj
  end
end

class Ten05
  attr_accessor :f1, :f2, :f3, :f4, :f5, :f6, :f7, :f8, :f9, :f10

  def initialize(
    f1: nil,
    f2: nil,
    f3: false,
    f4: 0,
    f5: 0,
    f6: 0,
    f7: 0,
    f8: 0,
    f9: 0,
    f10: 0
  )
    @f1 = f1
    @f2 = f2
    @f3 = f3
    @f4 = f4
    @f5 = f5
    @f6 = f6
    @f7 = f7
    @f8 = f8
    @f9 = f9
    @f10 = f10
  end
end

module Ten05Methods
  def self.write_ten05(w, obj)
    w.begin_object(10)
    w.write_field("f1")
    w.write_bytes(obj.f1)
    w.write_field("f2")
    w.write_string(obj.f2)
    w.write_field("f3")
    w.write_bool(obj.f3)
    w.write_field("f4")
    w.write_int32(obj.f4)
    w.write_field("f5")
    w.write_int32(obj.f5)
    w.write_field("f6")
    w.write_int32(obj.f6)
    w.write_field("f7")
    w.write_int64(obj.f7)
    w.write_field("f8")
    w.write_uint32(obj.f8)
    w.write_field("f9")
    w.write_uint32(obj.f9)
    w.write_field("f10")
    w.write_uint32(obj.f10)
    w.end_object
  end

  def self.decode_ten05(r)
    r.begin_object
    obj = Ten05.new
    while r.has_next_field
      key = r.read_field_name
      if key == "f1" then obj.f1 = r.read_bytes; next; end
      if key == "f2" then obj.f2 = r.read_string; next; end
      if key == "f3" then obj.f3 = r.read_bool; next; end
      if key == "f4" then obj.f4 = r.read_int32; next; end
      if key == "f5" then obj.f5 = r.read_int32; next; end
      if key == "f6" then obj.f6 = r.read_int32; next; end
      if key == "f7" then obj.f7 = r.read_int64; next; end
      if key == "f8" then obj.f8 = r.read_uint32; next; end
      if key == "f9" then obj.f9 = r.read_uint32; next; end
      if key == "f10" then obj.f10 = r.read_uint32; next; end
      r.skip
    end
    r.end_object
    obj
  end
end

